using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
    int CountSentences(string text);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that ranks sentences by word-frequency
/// scoring and returns the top-ranked sentences in their original order.
/// </summary>
public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
        "this", "that", "from", "as", "be", "been", "being", "have", "has",
        "had", "do", "does", "did", "will", "would", "could", "should",
        "may", "might", "shall", "can", "not", "no", "so", "if", "then",
        "than", "too", "very", "just", "about", "up", "out", "into"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitSentences(documentText);

        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        var topIndices = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    public int CountSentences(string text) => SplitSentences(text).Length;

    private static string[] SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();
    }

    private static Dictionary<string, int> BuildWordFrequencies(string[] sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies.TryGetValue(word, out int count);
                    frequencies[word] = count + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        string[] sentences, Dictionary<string, int> wordFrequencies)
    {
        int maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();

        return sentences.Select((sentence, index) =>
        {
            var words = ExtractWords(sentence);
            if (words.Length == 0) return (index, 0.0);

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => (double)wordFrequencies[w] / maxFreq);

            // Normalize by sentence length to avoid bias toward long sentences
            return (index, score / words.Length);
        }).ToList();
    }

    private static string[] ExtractWords(string text)
    {
        return WordRegex().Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToArray();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = _summaryService.CountSentences(request.DocumentText),
            SummarySentenceCount = _summaryService.CountSentences(summary)
        });
    }
}

